# checkers.py

def initialize_board():
    board = [[" " for _ in range(8)] for _ in range(8)]
    # Place pieces
    for i in range(3):
        for j in range(0, 8, 2):
            if (i + j) % 2 == 1:
                board[i][j] = "B"
    for i in range(5, 8):
        for j in range(0, 8, 2):
            if (i + j) % 2 == 1:
                board[i][j] = "W"
    return board

def print_board(board):
    for row in board:
        print(" ".join(row))

def is_valid_move(board, start_pos, end_pos):
    x1, y1 = start_pos
    x2, y2 = end_pos
    # Check if move is diagonal
    if abs(x1 - x2) != 1 or abs(y1 - y2) != 1:
        return False
    # Check if destination is empty
    if board[x2][y2] != " ":
        return False
    # Check capture rule for kings and normal pieces
    if (board[x1][y1].isupper() or board[x1][y1].lower() == 'k') and x2 < x1:
        return False
    if (board[x1][y1].islower() or board[x1][y1] == 'K') and x2 > x1:
        return False
    return True

def make_move(board, start_pos, end_pos):
    x1, y1 = start_pos
    x2, y2 = end_pos
    board[x2][y2] = board[x1][y1]
    board[x1][y1] = " "
    # Check for capture
    if abs(x1 - x2) == 2 and abs(y1 - y2) == 2:
        board[(x1 + x2) // 2][(y1 + y2) // 2] = " "
    return board

def is_game_over(board):
    # Check for win condition (one side has no pieces left)
    black_pieces = sum(row.count('B') + row.count('K') for row in board)
    white_pieces = sum(row.count('W') + row.count('k') for row in board)
    if black_pieces == 0:
        print("White wins!")
        return True
    elif white_pieces == 0:
        print("Black wins!")
        return True
    # Check for draw condition (no valid moves)
    valid_moves = False
    for i in range(8):
        for j in range(8):
            if board[i][j].isalpha():
                for dx, dy in [(-1, -1), (-1, 1), (1, -1), (1, 1)]:
                    new_x, new_y = i + dx * 2, j + dy * 2
                    if 0 <= new_x < 8 and 0 <= new_y < 8:
                        if is_valid_move(board, (i, j), (new_x, new_y)):
                            valid_moves = True
    if not valid_moves:
        print("Draw!")
        return True
    return False

def main():
    board = initialize_board()
    current_player = "B"
    while not is_game_over(board):
        print_board(board)
        start_pos = input(f"{current_player}'s turn. Enter starting position (e.g., 0 1): ").split()
        end_pos = input("Enter ending position (e.g., 2 3): ").split()
        start_pos = tuple(map(int, start_pos))
        end_pos = tuple(map(int, end_pos))
        if is_valid_move(board, start_pos, end_pos):
            board = make_move(board, start_pos, end_pos)
            current_player = "W" if current_player == "B" else "B"
        else:
            print("Invalid move. Try again.")
    print_board(board)

if __name__ == "__main__":
    main()
